import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

public List<TreeNode> delNodes(TreeNode root, int[] to_delete) {
    Set<Integer> to_delete_set = new HashSet<>();
    for (int i : to_delete) to_delete_set.add(i);
    List<TreeNode> remaining_trees = new ArrayList<>();

    TreeNode removeNodes(TreeNode node) {
        if (node == null) return null;
        node.left = removeNodes(node.left);
        node.right = removeNodes(node.right);
        if (to_delete_set.contains(node.val)) {
            if (node.left != null) remaining_trees.add(node.left);
            if (node.right != null) remaining_trees.add(node.right);
            return null;
        }
        return node;
    }

    if (removeNodes(root) != null) remaining_trees.add(root);
    return remaining_trees;
}
```


